customScripts.step_nav:
(function(root){
  var attempts = 0, maxAttempts = 40;
  function init() {
    var container = root.closest ? root.closest('.cel-rsvp-stepped') : null;
    if (!container) container = document.querySelector('.cel-rsvp-stepped');
    if (!container) {
      if (++attempts < maxAttempts) { setTimeout(init, 100); }
      return;
    }
    if (container.dataset.crsBound === '1') return;
    container.dataset.crsBound = '1';

    var currentStep = 1;
    var totalSteps = 3;

    function $$(sel, el) { return Array.prototype.slice.call((el||container).querySelectorAll(sel)); }
    function $(sel, el) { return (el||container).querySelector(sel); }

    function render() {
      $$('.crs-step').forEach(function(s){
        var stepNum = parseInt(s.getAttribute('data-step'), 10);
        s.style.display = stepNum === currentStep ? 'block' : 'none';
      });
      var pct = (currentStep / totalSteps) * 100;
      var bar = $('.crs-progress-bar');
      if (bar) bar.style.width = pct + '%';
      $$('.crs-step-tab').forEach(function(tab){
        var stepNum = parseInt(tab.getAttribute('data-step-tab'), 10);
        tab.classList.remove('crs-tab-active','crs-tab-completed','crs-tab-upcoming');
        if (stepNum === currentStep) tab.classList.add('crs-tab-active');
        else if (stepNum < currentStep) tab.classList.add('crs-tab-completed');
        else tab.classList.add('crs-tab-upcoming');
      });
      var prevBtn = $('.crs-btn-prev');
      var nextBtn = $('.crs-btn-next');
      var submitBtn = $('.crs-btn-submit');
      if (prevBtn) prevBtn.style.display = currentStep > 1 ? 'inline-flex' : 'none';
      if (nextBtn) nextBtn.style.display = currentStep < totalSteps ? 'inline-flex' : 'none';
      if (submitBtn) submitBtn.style.display = currentStep === totalSteps ? 'inline-flex' : 'none';
    }

    function validateStep(stepNum) {
      var stepEl = $('.crs-step[data-step="' + stepNum + '"]');
      if (!stepEl) return true;
      var invalid = [];
      $$('input, select, textarea', stepEl).forEach(function(el){
        if (el.hasAttribute('required') && !el.checkValidity()) {
          invalid.push(el);
        }
      });
      var radioGroups = {};
      $$('input[type="radio"][required]', stepEl).forEach(function(r){
        if (!radioGroups[r.name]) radioGroups[r.name] = [];
        radioGroups[r.name].push(r);
      });
      Object.keys(radioGroups).forEach(function(name){
        var checked = radioGroups[name].some(function(r){ return r.checked; });
        if (!checked) invalid.push(radioGroups[name][0]);
      });
      if (invalid.length) {
        invalid[0].focus();
        invalid[0].reportValidity && invalid[0].reportValidity();
        return false;
      }
      return true;
    }

    container.addEventListener('click', function(e){
      var t = e.target.closest ? e.target.closest('.crs-btn-next, .crs-btn-prev, .crs-step-tab') : null;
      if (!t) return;
      if (t.classList.contains('crs-btn-next')) {
        e.preventDefault();
        if (validateStep(currentStep) && currentStep < totalSteps) {
          currentStep++;
          render();
          try { window.scrollTo({ top: container.getBoundingClientRect().top + window.scrollY - 20, behavior: 'smooth' }); } catch(e){}
        }
      } else if (t.classList.contains('crs-btn-prev')) {
        e.preventDefault();
        if (currentStep > 1) { currentStep--; render(); }
      } else if (t.classList.contains('crs-step-tab')) {
        var target = parseInt(t.getAttribute('data-step-tab'), 10);
        if (target < currentStep) {
          currentStep = target; render();
        } else if (target > currentStep) {
          var ok = true;
          for (var i = currentStep; i < target; i++) {
            if (!validateStep(i)) { ok = false; break; }
          }
          if (ok) { currentStep = target; render(); }
        }
      }
    });

    render();
  }
  init();
})(window.__mfCurrentScriptRoot || document);

settings.customCss:
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap');

/* ===== Scope root + CSS vars (theme_selector overrides) ===== */
.cel-rsvp-stepped {
  --background: oklch(0.97 0.015 350);
  --foreground: oklch(0.25 0.03 350);
  --card: oklch(0.995 0.008 350);
  --primary: oklch(0.55 0.14 350);
  --primary-foreground: oklch(0.99 0 0);
  --secondary: oklch(0.92 0.03 350);
  --muted: oklch(0.94 0.015 350);
  --muted-foreground: oklch(0.50 0.03 350);
  --accent: oklch(0.70 0.10 20);
  --border: oklch(0.88 0.02 350);
  --input: oklch(0.94 0.015 350);
  --ring: oklch(0.55 0.14 350);

  display: block !important;
  width: 100% !important;
  position: relative;
  font-family: 'Inter', system-ui, sans-serif !important;
  color: var(--foreground);
  box-sizing: border-box;
  overflow: hidden !important;

  background-image:
    linear-gradient(135deg,
      color-mix(in oklab, var(--primary) 90%, transparent),
      color-mix(in oklab, var(--primary) 80%, transparent),
      color-mix(in oklab, var(--accent) 70%, transparent)),
    url('https://images.unsplash.com/photo-1519167758481-83f550bb49b3?w=1920&q=80') !important;
  background-size: auto, cover !important;
  background-position: center, center !important;
  background-repeat: no-repeat, no-repeat !important;
  background-attachment: scroll, scroll !important;
  isolation: isolate !important;
}
.cel-rsvp-stepped *,
.cel-rsvp-stepped *::before,
.cel-rsvp-stepped *::after { box-sizing: border-box; }

/* ===== Background layers ===== */
/* ===== Content wrapper ===== */
.cel-rsvp-stepped .crs-content {
  position: relative; z-index: 1;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px 16px;
}
@media (min-width: 768px) {
  .cel-rsvp-stepped .crs-content { padding: 40px 16px; }
}
.cel-rsvp-stepped .crs-container {
  width: 100% !important;
  max-width: 672px !important;
  margin: 0 auto !important;
  box-sizing: border-box;
